"use client";

import ScreenLayout from "@/components/ScreenLayout";
import { userSignin } from "@/httpclients/httpclient";
import Link from "next/link";
import { useRouter } from "next/navigation";
import React, { useState } from "react";

const SignIn = () => {
  const router = useRouter();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  function signin() {
    userSignin(email, password)
      .then((c) => {
        localStorage.setItem("token", c.data.token);
      })
      .then(() => router.push("/"))
      .catch((err) => {
        alert("Signin failed: " + (err.response?.data?.message || err.message));
      });
  }
  return (
    <ScreenLayout className="flex justify-center items-center ">
      <div className="min-w-lg shadow-card flex flex-col p-4 rounded-md bg-bg-side">
        <h1 className="text-2xl  my-4 font-bold w-full flex justify-center">
          Signin
        </h1>
        <label htmlFor="email" className="font-semibold text-lg">
          Email
        </label>
        <input
          onChange={(e) => setEmail(e.target.value)}
          type="text"
          id="email"
          className="outline-none border-border border rounded-lg px-4 py-1 text-lg mb-4"
        />
        <label htmlFor="password" className="font-semibold text-lg my-2">
          Password
        </label>
        <input
          onChange={(e) => setPassword(e.target.value)}
          type="text"
          id="password"
          className="outline-none border-border border rounded-lg px-4 py-1 text-lg"
        />
        <p className="font-medium my-2">
          If not has account please{" "}
          <Link
            href={"/signup"}
            className="font-bold hover:font-semibold text-blue-500 underline "
          >
            SignUp
          </Link>
        </p>
        <button
          onClick={() => signin()}
          className="bg-btn-sec py-2 rounded-xl hover:bg-btn-pri hover:text-shadow-btn-pri font-bold text-lg my-4"
        >
          Submit
        </button>
      </div>
    </ScreenLayout>
  );
};

export default SignIn;
